import {
    Home,
    Box,
    DollarSign,
    Tag,
    Clipboard,
    Camera,
    AlignLeft,
    UserPlus,
    Users,
    Chrome,
    BarChart,Settings,Archive, LogIn
} from 'react-feather';
export const MENUITEMS = [
    {
        path: '/dashboard', title: 'Dashboard', icon: Home, type: 'link', badgeType: 'primary', active: false
    },
    {
        title: 'Projects', icon: Box, type: 'sub', active: false, children: [
            { path: '/projects/add-project', title: 'Add Project', type: 'link' },
            { path: '/projects/product-list', title: 'Project List', type: 'link' },
        ]
    },
    {
        title: 'Nodes', icon: Tag, type: 'sub', active: false, children: [
            { path: '/nodes/list-nodes', title: 'List Node', type: 'link' },
            { path: '/nodes/create-nodes', title: 'Create Node', type: 'link' },
        ]
    },
    {
        title: 'Sources', icon: Clipboard , type: 'sub', active: false, children: [
            { path: '/sources/list-source', title: 'List Source', type: 'link' },
            { path: '/sources/create-source', title: 'Create Source', type: 'link' },
        ]
    },
    {
        title: 'Users', icon: UserPlus, type: 'sub', active: false, children: [
            { path: '/users/list-user', title: 'User List', type: 'link' },
            { path: '/users/create-user', title: 'Create User', type: 'link' },
        ]
    },
    {
        title: 'Reports',path:'/reports/report', icon: BarChart, type: 'link', active: false
    },
    {
        title: 'Settings',path:'/settings', icon: Settings, type: 'link', active: false
    },
    {
        title: 'History',path:'/invoice', icon: Archive, type: 'link', active: false
    },
    {
        title: 'Login',path:'/auth/login', icon: LogIn, type: 'link', active: false
    }
]
